#include <numeric>

#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    int divide(int dividend, int divisor) {
        long long MIN_INT = -2147483648, MAX_INT = 2147483647;
        bool sign = (dividend < 0) ^ (divisor < 0);
        long long absDividend = abs((long long)dividend);
        long long absDivisor = abs((long long)divisor);
        long long quotient = 0;
        while (absDividend >= absDivisor) {
            long long temp = absDivisor;
            long long i = 1;
            while ((temp << 1) <= absDividend) {
                temp <<= 1;
                i <<= 1;
            }
            absDividend -= temp;
            quotient += i;
        }
        quotient = sign ? -quotient : quotient;
        return max((int)MIN_INT, min((int)MAX_INT, (int)quotient));
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int dividend;
    if (!(cin >> dividend)) return 0;
    int divisor;
    if (!(cin >> divisor)) return 0;
    Solution sol;
    int ans = sol.divide(dividend, divisor);
    cout << ans << endl;
    return 0;
}
